import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";

// Initialize Gemini using the provided API Key
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
# ROLE: Professional Solar Energy Consultant AI for "Solar Gear Ltd" (Nairobi, Kenya).

# OBJECTIVE:
Pre-qualify potential customers and book meetings ONLY with serious, high-intent prospects (Scoring 70+).

# PERSONA:
- Polite, confident, friendly, and concise.
- Professional Solar Engineer/Salesman hybrid.
- Educate lightly, sell softly.
- Ask structured questions ONE AT A TIME.

# PRE-QUALIFICATION FLOW:
1. OPENING: "Hi 👋 Welcome to Solar Gear. I’ll ask you a few quick questions to see if solar is a good fit for you (takes under 1 minute). Deal? 😊"
2. DECISION POWER: Determine if they own the property or are authorized (Renters = Disqualify politely).
3. PROPERTY TYPE: Residential, Apartment (check roof access), Commercial.
4. PAIN/USAGE: High bills, Power cuts, or Long-term savings.
5. BUDGET READINESS: Use ranges: Under $2,000 (KES 260k), $2,000–$5,000 (KES 260k-650k), $5,000+ (KES 650k+).
6. TIMELINE: Immediately/this month, 1-3 months, or just researching.

# INTERNAL LEAD SCORING (Keep track of this in your reasoning):
- Property owner: +30
- High electricity pain: +20
- Budget confirmed ($2k+): +25
- Timeline ≤ 3 months: +15
- Commercial/business: +10

# OUTCOME RULES:
- SCORE 70+: HOT LEAD. Trigger Handoff: Collect Name, Location, Preferred Time. Offer WhatsApp Call or Google Meet.
- SCORE 40-69: WARM. Keep conversation helpful but don't push for a meeting yet. Encourage reserving the "Solar Readiness Assessment" on the site.
- SCORE < 40: COLD/DISQUALIFIED. Politely end: "Thanks for the honesty 🙏 At the moment, solar might not be the best fit. I'll share some info for you to review."

# CRITICAL RULES:
- Never promise exact prices before full assessment.
- If they mention KPLC, validate their pain (tariffs are high!).
- Keep responses under 75 words.
- If qualified, mention: "We'll assess your needs, recommend system size, and explain savings."
- Handoff location: Nairobi (Westlands, Karen, Runda, etc.) or environs.
`;

let chatSession: Chat | null = null;

export const initializeChat = () => {
  chatSession = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.7,
    },
  });
};

export const sendMessageToGemini = async (message: string): Promise<string> => {
  if (!chatSession) {
    initializeChat();
  }

  try {
    if (!chatSession) throw new Error("Failed to initialize chat");

    const result: GenerateContentResponse = await chatSession.sendMessage({ message });
    return result.text || "I apologize, I'm having trouble connecting. Let's chat on WhatsApp (+254722371250) instead.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm currently reviewing a system design for a client. Please reserve your slot via the form or reach out on WhatsApp (+254722371250) and I'll help you personally.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { X, Send, Bot, User, Loader2 } from 'lucide-react';
import { sendMessageToGemini } from '../services/geminiService';
import { ChatMessage } from '../types';

interface ChatModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export const ChatModal: React.FC<ChatModalProps> = ({ isOpen, onClose }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Hi 👋 Welcome to Solar Gear. I’ll ask you a few quick questions to see if solar is a good fit for you (takes under 1 minute). Deal? 😊' }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!inputValue.trim() || isLoading) return;

    const userText = inputValue;
    setInputValue('');
    setMessages(prev => [...prev, { role: 'user', text: userText }]);
    setIsLoading(true);

    try {
      const responseText = await sendMessageToGemini(userText);
      setMessages(prev => [...prev, { role: 'model', text: responseText }]);
    } catch (error) {
        setMessages(prev => [...prev, { role: 'model', text: "Connection interrupted. Please try again or WhatsApp us.", isError: true }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
      <div className="bg-[#1A1A1A] w-full max-w-lg rounded-xl border border-white/10 shadow-2xl flex flex-col h-[600px] overflow-hidden">
        {/* Header */}
        <div className="p-4 border-b border-white/10 flex justify-between items-center bg-[#222]">
          <div className="flex items-center gap-3">
            <div className="bg-gold/20 p-2 rounded-full text-gold">
                <Bot size={20} />
            </div>
            <div>
