import React, { useState, useEffect, Suspense, lazy } from 'react';
import { Header } from './components/Header';
import { Hero } from './components/Hero';
import { MessageCircle, Loader2, X, Sparkles } from 'lucide-react';
import { trackWhatsAppClick, trackEvent } from './lib/analytics';
import { motion, AnimatePresence } from 'framer-motion';

// Lazy load heavy components
const ProblemSection = lazy(() => import('./components/ProblemSection').then(m => ({ default: m.ProblemSection })));
const CalculatorSection = lazy(() => import('./components/CalculatorSection').then(m => ({ default: m.CalculatorSection })));
const PackageSelectionGuide = lazy(() => import('./components/PackageSelectionGuide').then(m => ({ default: m.PackageSelectionGuide })));
const PackagesSection = lazy(() => import('./components/PackagesSection').then(m => ({ default: m.PackagesSection })));
const ProductSpotlight = lazy(() => import('./components/ProductSpotlight').then(m => ({ default: m.ProductSpotlight })));
const SocialProof = lazy(() => import('./components/SocialProof').then(m => ({ default: m.SocialProof })));
const TestimonialCarousel = lazy(() => import('./components/TestimonialCarousel').then(m => ({ default: m.TestimonialCarousel })));
const OfferSection = lazy(() => import('./components/OfferSection').then(m => ({ default: m.OfferSection })));
const RiskReversal = lazy(() => import('./components/RiskReversal').then(m => ({ default: m.RiskReversal })));
const LeadMagnet = lazy(() => import('./components/LeadMagnet').then(m => ({ default: m.LeadMagnet })));
const FAQ = lazy(() => import('./components/FAQ').then(m => ({ default: m.FAQ })));
const Footer = lazy(() => import('./components/Footer').then(m => ({ default: m.Footer })));
const ChatModal = lazy(() => import('./components/ChatModal').then(m => ({ default: m.ChatModal })));
const PackagePurchaseModal = lazy(() => import('./components/PackagePurchaseModal').then(m => ({ default: m.PackagePurchaseModal })));
const PrivacyPolicy = lazy(() => import('./components/PrivacyPolicy').then(m => ({ default: m.PrivacyPolicy })));

const SectionLoader = () => (
  <div className="w-full h-40 flex items-center justify-center bg-charcoal">
    <Loader2 className="text-gold/20 animate-spin" size={24} />
  </div>
);

function App() {
  const [currentPage, setCurrentPage] = useState<'home' | 'privacy'>('home');
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [showGreeting, setShowGreeting] = useState(false);
  const [prefillChatMessage, setPrefillChatMessage] = useState<string | null>(null);
  const [purchaseModal, setPurchaseModal] = useState<{ isOpen: boolean; packageName: string }>({
    isOpen: false,
    packageName: ''
  });

  useEffect(() => {
    // Show proactive greeting after 5 seconds
    const timer = setTimeout(() => setShowGreeting(true), 5000);

    const handleHashChange = () => {
      const hash = window.location.hash;
      if (hash === '#privacy') {
        setCurrentPage('privacy');
        window.scrollTo(0, 0);
      } else {
        setCurrentPage('home');
      }
    };
    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();
    return () => {
      window.removeEventListener('hashchange', handleHashChange);
      clearTimeout(timer);
    };
  }, []);

  const handlePackageSelect = (name: string) => {
    setPurchaseModal({ isOpen: true, packageName: name });
  };

  const handleChatWithPackage = (packageName: string) => {
    setPrefillChatMessage(`I'm interested in the ${packageName}. Could you explain the technical specs and how it handles blackouts?`);
    setIsChatOpen(true);
    setShowGreeting(false);
  };

  const handleGeneralChat = () => {
    setPrefillChatMessage(`Hi! I'd like to speak with a solar engineer about my home's energy needs in Nairobi.`);
    setIsChatOpen(true);
    setShowGreeting(false);
  };

  const closeChat = () => {
    setIsChatOpen(false);
    setPrefillChatMessage(null);
  };

  const navigateToHome = () => {
    window.location.hash = '';
    setCurrentPage('home');
  };

  const navigateToPrivacy = () => {
    window.location.hash = 'privacy';
    setCurrentPage('privacy');
  };

  if (currentPage === 'privacy') {
    return (
      <div className="min-h-screen bg-charcoal text-white selection:bg-gold selection:text-charcoal font-sans">
        <Header onLogoClick={navigateToHome} />
        <Suspense fallback={<div className="h-screen bg-charcoal" />}>
          <PrivacyPolicy onBack={navigateToHome} />
          <Footer onPrivacyClick={navigateToPrivacy} />
        </Suspense>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-charcoal text-white selection:bg-gold selection:text-charcoal font-sans">
      <Header onLogoClick={navigateToHome} />

      <Hero 
        onChatClick={handleGeneralChat} 
        onProductClick={() => {
          const section = document.getElementById('packages');
          if (section) section.scrollIntoView({ behavior: 'smooth' });
        }}
      />

      <Suspense fallback={<SectionLoader />}>
        <ProblemSection />
        <CalculatorSection />
        <PackageSelectionGuide />
        <PackagesSection 
          onPackageSelect={handlePackageSelect} 
          onChatWithPackage={handleChatWithPackage}
        />
        <ProductSpotlight />
        <SocialProof />
        <TestimonialCarousel />
        <OfferSection />
        <RiskReversal />
        <LeadMagnet />
        <FAQ />
        <Footer onPrivacyClick={navigateToPrivacy} />

        <AnimatePresence>
          {isChatOpen && (
            <ChatModal 
              isOpen={isChatOpen} 
              prefillMessage={prefillChatMessage}
              onClose={closeChat} 
            />
          )}
        </AnimatePresence>

        {purchaseModal.isOpen && (
          <PackagePurchaseModal 
            isOpen={purchaseModal.isOpen}
            packageName={purchaseModal.packageName}
            onClose={() => setPurchaseModal({ ...purchaseModal, isOpen: false })}
          />
        )}
      </Suspense>

      {/* Persistent AI Chat Hub */}
      <div className="fixed bottom-6 right-6 z-[120] flex flex-col items-end gap-3 pointer-events-none">
        <AnimatePresence>
          {showGreeting && !isChatOpen && (
            <motion.div
              initial={{ opacity: 0, scale: 0.8, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.8 }}
              className="bg-white p-4 rounded-2xl rounded-br-none shadow-2xl border border-gold/20 max-w-[240px] pointer-events-auto relative mb-2"
            >
              <button 
                onClick={() => setShowGreeting(false)}
                className="absolute -top-2 -left-2 bg-charcoal text-white rounded-full p-1 border border-white/10 hover:bg-gold hover:text-charcoal transition-colors"
              >
                <X size={12} />
              </button>
              <div className="flex gap-2">
                <div className="w-8 h-8 rounded-full bg-gold/10 flex items-center justify-center shrink-0">
                   <Sparkles size={14} className="text-gold" />
                </div>
                <p className="text-[11px] text-charcoal font-bold leading-tight">
                  Hi! 👋 I'm your AI Solar Engineer. Want a quick estimate for your home?
                </p>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        <button
          onClick={handleGeneralChat}
          className="pointer-events-auto bg-gold text-charcoal p-4 rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-all group flex items-center gap-3 border-4 border-charcoal relative overflow-hidden"
          aria-label="Open AI Solar Hub"
        >
          <div className="absolute inset-0 bg-white/20 -translate-x-full group-hover:translate-x-0 transition-transform duration-500"></div>
          <div className="relative">
            <MessageCircle size={32} strokeWidth={2.5} />
            <span className="absolute -top-1 -right-1 w-3 h-3 bg-green-500 rounded-full border-2 border-charcoal animate-pulse"></span>
          </div>
          <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-500 whitespace-nowrap font-black text-sm uppercase tracking-widest px-0 group-hover:pr-2">
            Ask Engineer
          </span>
        </button>
      </div>
    </div>
  );
}

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { X, Send, Bot, User, Loader2, Database, MessageCircle, Calendar, ExternalLink, Sparkles } from 'lucide-react';
import { sendMessageToGemini } from '../services/geminiService';
import { ChatMessage } from '../types';
import { trackLeadSubmission, trackWhatsAppClick, trackEvent } from '../lib/analytics';
import { motion } from 'framer-motion';

interface ChatModalProps {
  isOpen: boolean;
  onClose: () => void;
  prefillMessage?: string | null;
}

const CALENDLY_URL = "https://calendly.com/solargearlrd/30min";
const WHATSAPP_FALLBACK = "I'm having a temporary connection issue. Please try again in a moment or use the WhatsApp option to connect directly with our engineers.";

export const ChatModal: React.FC<ChatModalProps> = ({ isOpen, onClose, prefillMessage }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Hi 👋 Welcome to Solar Gear. Are you looking for a solar solution for your Home, Business, or an Apartment here in Nairobi? 😊' }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const hasPrefilled = useRef(false);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  useEffect(() => {
    if (isOpen && prefillMessage && !hasPrefilled.current) {
      hasPrefilled.current = true;
      handleSend(prefillMessage);
    }
  }, [isOpen, prefillMessage]);

  const handleSend = async (textToOverride?: string) => {
    const textToSend = textToOverride || inputValue;
    if (!textToSend.trim() || isLoading) return;

    if (!textToOverride) setInputValue('');
    setMessages(prev => [...prev, { role: 'user', text: textToSend }]);
    setIsLoading(true);

    try {
      const responseText = await sendMessageToGemini(textToSend);
      const isSystemError = responseText.includes("temporary connection issue") || responseText.includes("WhatsApp option");
      const isBookingReady = responseText.includes("calendly.com") || responseText.includes("book your slot");

      if (responseText.toLowerCase().includes("notified our engineering") || responseText.toLowerCase().includes("details received")) {
        trackLeadSubmission('chat'); 
      }

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: responseText, 
        isError: isSystemError,
        isBooking: isBookingReady
      }]);
    } catch (error) {
        setMessages(prev => [...prev, { 
          role: 'model', 
          text: WHATSAPP_FALLBACK, 
          isError: true 
        }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleWhatsAppEscalation = () => {
    trackWhatsAppClick('chat_modal');
    window.open("https://wa.me/254722371250?text=Hi%20Solar%20Gear%2C%20I'm%20chatting%20with%20your%20AI%20but%20want%20to%20speak%20with%20a%20human%20engineer%20now.", "_blank");
  };

  if (!isOpen) return null;

  return (
    <motion.div 
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-[150] flex items-end md:items-center justify-center p-0 md:p-4 bg-black/80 backdrop-blur-sm"
    >
      <motion.div 
        initial={{ y: 100, scale: 0.95 }}
        animate={{ y: 0, scale: 1 }}
        exit={{ y: 100, scale: 0.95 }}
        className="bg-[#1A1A1A] w-full max-w-lg rounded-t-[2rem] md:rounded-3xl border border-white/10 shadow-2xl flex flex-col h-[85vh] md:h-[650px] overflow-hidden"
      >
        {/* Header */}
        <div className="p-4 md:p-6 border-b border-white/10 flex justify-between items-center bg-[#222]">
          <div className="flex items-center gap-3">
            <div className="bg-gold/20 p-2.5 rounded-xl text-gold">
                <Sparkles size={20} />
            </div>
            <div>
                <h3 className="text-white font-bold text-sm">Engineer AI Hub</h3>
                <div className="flex items-center gap-1.5 mt-0.5">
                  <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
                  <p className="text-[10px] text-gray-400 uppercase font-black tracking-widest">Live in Nairobi</p>
                </div>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button 
              onClick={handleWhatsAppEscalation}
              className="bg-[#25D366]/10 text-[#25D366] px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest border border-[#25D366]/20 hover:bg-[#25D366] hover:text-white transition-all hidden sm:flex items-center gap-2"
            >
              <MessageCircle size={14} /> WhatsApp
            </button>
            <button onClick={onClose} className="text-gray-400 hover:text-white transition-colors p-1">
              <X size={24} />
            </button>
          </div>
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 bg-charcoal custom-scrollbar">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div 
                className={`max-w-[90%] p-4 rounded-2xl text-sm leading-relaxed ${
                  msg.role === 'user' 
                    ? 'bg-gold text-charcoal font-bold rounded-tr-none' 
                    : msg.isError 
                      ? 'bg-red-500/10 text-red-200 border border-red-500/20 rounded-tl-none shadow-lg'
                      : 'bg-white/5 text-gray-200 border border-white/10 rounded-tl-none shadow-lg'
                }`}
              >
                {msg.text}

                {(msg.isError || msg.isBooking || msg.text.includes(CALENDLY_URL)) && (
                  <div className="mt-4 flex flex-col gap-2">
                    <a 
                      href={CALENDLY_URL}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex items-center justify-center gap-2 bg-gold text-charcoal py-3 px-4 rounded-xl font-black text-xs hover:bg-gold-light transition-all shadow-lg shadow-gold/20"
                    >
                      <Calendar size={14} /> Book Site Visit <ExternalLink size={12} />
                    </a>
                    {msg.isError && (
                      <button 
                        onClick={handleWhatsAppEscalation}
                        className="flex items-center justify-center gap-2 bg-[#25D366] text-white py-3 px-4 rounded-xl font-bold text-xs hover:bg-[#1ebc57] transition-colors"
                      >
                        <MessageCircle size={14} /> Talk to Human Engineer
                      </button>
                    )}
                  </div>
                )}
              </div>
            </div>
          ))}
          {isLoading && (
             <div className="flex justify-start">
               <div className="bg-white/5 p-4 rounded-2xl rounded-tl-none border border-white/10 flex flex-col gap-2">
                 <div className="flex gap-1">
                    <span className="w-1.5 h-1.5 bg-gold rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></span>
                    <span className="w-1.5 h-1.5 bg-gold rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></span>
                    <span className="w-1.5 h-1.5 bg-gold rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></span>
                 </div>
                 <div className="text-[10px] text-gray-500 uppercase tracking-tighter flex items-center gap-1 font-bold">
                   <Database size={10} className="animate-pulse" /> Engineering Link Active...
                 </div>
               </div>
             </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <div className="p-4 md:p-6 border-t border-white/10 bg-[#222]">
          <div className="flex gap-2">
            <input 
              type="text" 
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Type your solar question..." 
              className="flex-1 bg-[#111] border border-white/10 rounded-2xl px-5 py-4 text-white focus:outline-none focus:border-gold transition-colors text-[15px]"
              autoFocus
            />
            <button 
              onClick={() => handleSend()}
              disabled={isLoading || !inputValue.trim()}
              className="bg-gold hover:bg-gold-light text-charcoal p-4 rounded-2xl disabled:opacity-50 transition-all shadow-lg shadow-gold/10 active:scale-95 shrink-0"
            >
              <Send size={24} />
            </button>
